function(){
  var fid = {{Franchise ID}};
  if(fid == ''){
    fid = '(not set)';
  }
  return fid;
}

function() {

  var event = {{Event}};
  var analyticsAccountArray = {{Data Layer - Analytics ID}};
  var globalUA = 'UA-48391737-2';
  if(document.location.href.indexOf('staging') > -1 || {{Debug Mode}} == true){
    globalUA = 'UA-48391737-3';
  }

  var UA = '';
  event.match(/\.0$/) ? UA = globalUA : 
  event.match(/\.1$/) ? UA = analyticsAccountArray[0] :
  event.match(/\.2$/) ? UA = analyticsAccountArray[1] :
  event.match(/\.3$/) ? UA = analyticsAccountArray[2] :
  event.match(/\.4$/) ? UA = analyticsAccountArray[3] :
  event.match(/\.5$/) ? UA = analyticsAccountArray[4] :
  UA = 'UA-XXXX-XX';

  return UA;
}

function(){
	var t = {{Page URL}};
	var h = t.split('?address=');
	var k = h[1].replace(/\+/g,' ');
	return k
}

