function() {

  var franchiseUUIDFromDL = {{DLV | officeID (UUID)}}; 
  var officeIdStringFromDL = {{DLV | Office ID}}; 
  var currentPagePath = {{Page Path}}; 
  var franchisesList = {{CJS | Combined Franchises List}}; 
  if (!franchiseUUIDFromDL || typeof franchiseUUIDFromDL !== 'string' || franchiseUUIDFromDL.trim() === "") {
    return 'not_valid_missing_franchise_uuid_dl';
  }
  if (!officeIdStringFromDL || typeof officeIdStringFromDL !== 'string' || officeIdStringFromDL.trim() === "") {

    return 'not_valid_missing_office_id_string_dl';
  }
  if (!currentPagePath || typeof currentPagePath !== 'string') {

    return 'not_valid_missing_page_path';
  }
  if (typeof franchisesList !== 'object' || franchisesList === null) {

    return 'not_valid_franchise_list_unavailable';
  }


  var normalizedFranchiseUUID = franchiseUUIDFromDL.trim(); 
  var normalizedOfficeIdStringFromDL = officeIdStringFromDL.trim().toLowerCase();
  var normalizedCurrentPagePath = currentPagePath.toLowerCase();
  var franchiseDetails = franchisesList[normalizedFranchiseUUID];

  if (!franchiseDetails) {

    return 'not_valid_unknown_franchise_uuid';
  }


  if (typeof franchiseDetails.office_id_string !== 'string' || 
      franchiseDetails.office_id_string.trim().toLowerCase() !== normalizedOfficeIdStringFromDL) {

    return 'not_valid_mismatched_dl_office_id_string';
  }


  if (typeof franchiseDetails.expected_url_path_segment !== 'string' || 
      normalizedCurrentPagePath.indexOf(franchiseDetails.expected_url_path_segment.toLowerCase()) !== 0) {

    return 'not_valid_url_for_franchise';
  }


  return 'valid_office_path';
}

